#include <bits/stdc++.h>
using namespace std;
#define int long long
const int maxn=5e5+5;
int n,d,k,dp[maxn],ans=-1,x[maxn],s[maxn];
bool check(int l,int r) {
	int q[n+5],h=1,t=0,cur=0;
	memset(dp,-127,sizeof(dp));
	dp[0]=0;
	q[h]=1;
	for(int i=1; i<=n; i++) {
		while(cur<i&&x[cur]<=x[i]-l) {
			if(dp[cur]>=INT_MIN) {
				while(h<=t&&dp[q[t]]<=dp[cur]) {
					t--;
				}
				q[++t]=cur;
			}
			cur++;
		}
		while(h<=t&&x[q[h]]<x[i]-r) {
			h++;
		}
		if(h<=t) {
			dp[i]=dp[q[h]]+s[i];
			if(dp[i]>k) {
				return 1;
			}
		}
	}
	return 0;
}
long long aa;
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	cin>>n>>d>>k;
	for(int i=1; i<=n; i++) {
		cin>>x[i]>>s[i];
	}
	int l=0,r=x[n];
	while(l<r) {
		int mid=l+r>>1;
		if(check(max(d-mid,1LL),d+mid)) {
			ans=mid;
			r=mid;
		} else {
			l=mid+1;
		}
	}
	cout<<ans;
	return 0;
}
